const { ApolloServer, gql } = require('apollo-server');

// Sample data
const users = [
  { id: '1', name: 'Alice' },
  { id: '2', name: 'Bob' }
];

const posts = [
  { id: '1', title: 'Post 1', userId: '1' },
  { id: '2', title: 'Post 2', userId: '2' }
];

const comments = [
  { id: '1', content: 'Comment 1', postId: '1', userId: '2' },
  { id: '2', content: 'Comment 2', postId: '2', userId: '1' }
];

// GraphQL schema
const typeDefs = gql`
  type User {
    id: ID!
    name: String!
    posts: [Post]
  }

  type Post {
    id: ID!
    title: String!
    user: User
    comments: [Comment]
  }

  type Comment {
    id: ID!
    content: String!
    user: User
    post: Post
  }

  type Query {
    users: [User]
    posts: [Post]
    comments: [Comment]
  }
`;

// Resolvers
const resolvers = {
  Query: {
    users: () => users,
    posts: () => posts,
    comments: () => comments
  },
  User: {
    posts: (parent) => posts.filter(post => post.userId === parent.id)
  },
  Post: {
    user: (parent) => users.find(user => user.id === parent.userId),
    comments: (parent) => comments.filter(comment => comment.postId === parent.id)
  },
  Comment: {
    user: (parent) => users.find(user => user.id === parent.userId),
    post: (parent) => posts.find(post => post.id === parent.postId)
  }
};

// Security: Depth Limiting
const depthLimit = require('graphql-depth-limit');

const server = new ApolloServer({
  typeDefs,
  resolvers,
  validationRules: [depthLimit(5)] // Limit query depth to prevent DoS attacks
});

server.listen().then(({ url }) => {
  console.log(`🚀 Server ready at ${url}`);
});